solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    int a {};
    int b {};
    std::cin >> a >> b;

    int    intResult   { a / b };
    double floatResult { static_cast<double>(a) / b };

    std::cout << "Integer: " << intResult << '\n';
    std::cout << "Float: "   << std::fixed << std::setprecision(2) << floatResult << '\n';
    return 0;
}

