solution_code:
#include <iostream>

int charToCode(char c)
{
    return static_cast<int>(c);
}

int main()
{
    char c {};
    std::cin >> c;
    std::cout << "Char: " << c << '\n';
    std::cout << "Code: " << charToCode(c) << '\n';
    return 0;
}
